/**
 * Handoff store v2 port.
 *
 * Replaces the pre-Phase-1 HandoffStorePort that was deleted along with
 * the prose-based handoff format. The new port stores UkiHandoff records
 * which are backed by the UKI v5.3 compressed-string format.
 *
 * Records are identified by a `YYYY-MM-DD-NNN` id generated by
 * `generateHandoffId()` in `src/domain/id.ts`.
 */
import type {
  CreateUkiHandoffInput,
  UkiHandoff,
  UkiHandoffStatus,
} from "../domain/uki-types.js";

export interface UpdateHandoffStatusMeta {
  readonly pickedUpBy?: string;
  readonly completedAt?: string;
  readonly report?: string;
}

export interface HandoffStorePort {
  /** Create a new handoff. Generates a new id and compresses the slots. */
  create(input: CreateUkiHandoffInput): Promise<UkiHandoff>;

  /**
   * Atomically claim a pending handoff, either by explicit id or by picking the
   * newest pending handoff. Returns the updated handoff, or undefined when the
   * requested handoff does not exist or is no longer pending.
   */
  claimPending(id?: string, pickedUpBy?: string): Promise<UkiHandoff | undefined>;

  /** Retrieve a handoff by id, or undefined if not found. */
  get(id: string): Promise<UkiHandoff | undefined>;

  /**
   * Return the most recent pending handoff (highest id by descending sort),
   * or undefined if none exists.
   */
  getLatestPending(): Promise<UkiHandoff | undefined>;

  /**
   * List all handoffs, optionally filtered by status. Sorted by id
   * descending (newest first).
   */
  list(filter?: { status?: UkiHandoffStatus }): Promise<readonly UkiHandoff[]>;

  /**
   * Transition a handoff's status and optionally set related metadata
   * (pickedUpBy on `picked-up`, completedAt + report on `completed`).
   * Returns the updated record, or undefined if the id was not found.
   */
  updateStatus(
    id: string,
    status: UkiHandoffStatus,
    meta?: UpdateHandoffStatusMeta,
  ): Promise<UkiHandoff | undefined>;

  /** Delete a handoff by id. Returns true if removed, false if not found. */
  delete(id: string): Promise<boolean>;
}
